import Link from "next/link";

interface ProjectMetaProps {
  client?: string;
  website?: { label: string; url: string };
  industry?: string;
  services: string;
  timeline?: string;
}

function MetaItem({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div className="flex flex-col gap-2">
      <span className="p3 text-[var(--color-gray-400)]">{label}</span>
      <span className="p1 text-[var(--color-fg)]">{children}</span>
    </div>
  );
}

export default function ProjectMeta({ client, website, industry, services, timeline }: ProjectMetaProps) {
  return (
    <div className="grid grid-cols-2 gap-8 md:grid-cols-3 lg:grid-cols-5 lg:gap-12">
      {client && <MetaItem label="Client">{client}</MetaItem>}

      {website && (
        <MetaItem label="Website">
          <Link
            href={website.url}
            target="_blank"
            rel="noopener noreferrer"
            className="inline-flex items-center gap-1 underline underline-offset-4"
          >
            {website.label}
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="16"
              height="16"
              viewBox="0 0 24 24"
              fill="none"
            >
              <path
                d="M7 7H17M17 7V17M17 7L7 17"
                stroke="currentColor"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          </Link>
        </MetaItem>
      )}

      {industry && <MetaItem label="Industry">{industry}</MetaItem>}

      <MetaItem label="Services">{services}</MetaItem>

      {timeline && <MetaItem label="Timeline">{timeline}</MetaItem>}
    </div>
  );
}
