import { notFound } from "next/navigation";
import Image from "next/image";
import { projects } from "@/lib/projects";
import type { Metadata } from "next";
import ProjectMeta from "@/components/ProjectMeta";
import ImageGallery from "@/components/ImageGallery";
import FooterSection from "@/components/sections/FooterSection";

type Props = {
  params: Promise<{ slug: string }>;
};

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { slug } = await params;
  const project = projects.find((p) => p.slug === slug);
  if (!project) return { title: "Not Found" };

  return {
    title: `${project.title} – VS Design`,
    description: project.services,
  };
}

export async function generateStaticParams() {
  return projects.map((p) => ({ slug: p.slug }));
}

export default async function WorkPage({ params }: Props) {
  const { slug } = await params;
  const project = projects.find((p) => p.slug === slug);

  if (!project) notFound();

  return (
    <main className="flex flex-1 flex-col overflow-y-auto">
      {/* ── Hero Image ─────────────────────────────────────────── */}
      {project.heroImage && (
        <div className="relative h-[360px] w-full md:h-[640px]">
          <Image
            src={project.heroImage}
            alt={project.title}
            fill
            className="object-cover"
            sizes="100vw"
            priority
          />
        </div>
      )}

      {/* ── Project Title ──────────────────────────────────────── */}
      <div className="mx-auto w-full max-w-[var(--max-w-desktop)] px-6 md:px-20">
        <h1 className="hero mt-16 text-center text-[48px] leading-[1.15] md:mt-24 md:text-[96px] md:leading-[115px] mx-auto max-w-[941px]">
          {project.title}
        </h1>

        {/* ── Metadata Grid ──────────────────────────────────── */}
        <div className="mt-12 md:mt-16">
          <ProjectMeta
            client={project.client}
            website={project.website}
            industry={project.industry}
            services={project.services}
            timeline={project.timeline}
          />
        </div>

        {/* ── Divider ────────────────────────────────────────── */}
        <hr className="mt-12 border-[var(--color-border)] md:mt-16" />

        {/* ── Content Blocks ─────────────────────────────────── */}
        {project.contentBlocks?.map((block, i) => (
          <div key={i}>
            <div className="mt-16 flex flex-col gap-8 md:mt-24 md:flex-row md:gap-[87px]">
              <h2 className="h2 shrink-0 md:max-w-[484px]">{block.heading}</h2>
              <div className="flex max-w-[609px] flex-col gap-6">
                {block.paragraphs.map((p, j) => (
                  <p key={j} className="p1 text-[var(--color-muted)]">
                    {p}
                  </p>
                ))}
              </div>
            </div>

            {/* Image block after each content block (if available) */}
            {project.imageBlocks?.[i] && (
              <div className="mt-12 md:mt-16">
                {project.imageBlocks[i].type === "single" && (
                  <div className="relative h-[400px] w-full overflow-hidden rounded-2xl md:h-[768px] md:max-w-[1280px]">
                    <Image
                      src={project.imageBlocks[i].images[0].src}
                      alt={project.imageBlocks[i].images[0].alt}
                      fill
                      className="object-cover"
                      sizes="(max-width: 768px) 100vw, 1280px"
                    />
                  </div>
                )}

                {project.imageBlocks[i].type === "double" && (
                  <div className="flex flex-col gap-6 md:flex-row md:gap-10">
                    {project.imageBlocks[i].images.map((img, k) => (
                      <div
                        key={k}
                        className="relative h-[320px] w-full overflow-hidden rounded-2xl md:h-[600px] md:w-[calc(50%-20px)]"
                      >
                        <Image
                          src={img.src}
                          alt={img.alt}
                          fill
                          className="object-cover"
                          sizes="(max-width: 768px) 100vw, 620px"
                        />
                      </div>
                    ))}
                  </div>
                )}

                {project.imageBlocks[i].type === "full" && (
                  <div className="relative h-[400px] w-full overflow-hidden rounded-2xl md:h-[896px] md:max-w-[1280px]">
                    <Image
                      src={project.imageBlocks[i].images[0].src}
                      alt={project.imageBlocks[i].images[0].alt}
                      fill
                      className="object-cover"
                      sizes="(max-width: 768px) 100vw, 1280px"
                    />
                  </div>
                )}
              </div>
            )}
          </div>
        ))}
      </div>

      {/* ── Horizontal Gallery ───────────────────────────────── */}
      {project.galleryImages && project.galleryImages.length > 0 && (
        <div className="mt-16 px-6 md:mt-24 md:px-20">
          <ImageGallery images={project.galleryImages} />
        </div>
      )}

      {/* ── Results Section ──────────────────────────────────── */}
      {project.results && (
        <div className="mx-auto w-full max-w-[var(--max-w-desktop)] px-6 md:px-20">
          <hr className="mt-16 border-[var(--color-border)] md:mt-24" />
          <div className="mt-16 flex flex-col gap-8 md:mt-24 md:flex-row md:gap-[87px]">
            <h2 className="h2 shrink-0 md:max-w-[484px]">{project.results.heading}</h2>
            <div className="flex max-w-[609px] flex-col gap-6">
              {project.results.paragraphs.map((p, j) => (
                <p key={j} className="p1 text-[var(--color-muted)]">
                  {p}
                </p>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ── Footer ───────────────────────────────────────────── */}
      <div className="mt-16 md:mt-24">
        <FooterSection />
      </div>
    </main>
  );
}
